     9→async function runCommand(cmd: string[]): Promise<ProcessResult> {
    10→  const proc = Bun.spawn(cmd, { stdout: "pipe", stderr: "pipe" });
    11→  const stdout = await new Response(proc.stdout).text();
    12→  const stderr = await new Response(proc.stderr).text();
    13→  const exitCode = await proc.exited;
    14→  return { stdout, stderr, exitCode };
    15→}
