    17→async function getPRUrl(prNumber: number): Promise<string | null> {
    18→  const result = await runCommand([
    19→    "gh",
    20→    "pr",
    21→    "view",
    22→    String(prNumber),
    23→    "--json",
    24→    "url",
    25→    "-q",
    26→    ".url",
    27→  ]);
