    41→async function runReviewer(skillName: string): Promise<Record<string, unknown>> {
    42→  const env = Object.fromEntries(
    43→    Object.entries(process.env).filter(([k]) => k !== "CLAUDECODE")
    44→  );
    45→
    46→  const cmd = ["claude", "-p", `/${skillName} ci`, "--output-format", "json"];
    47→  console.error(`Running command: ${cmd.join(" ")}`);
    48→
    49→  const proc = Bun.spawn(cmd, {
    50→    stdout: "pipe",
    51→    stderr: "pipe",
    52→    env,
    53→  });
    54→
    55→  const stdout = await new Response(proc.stdout).text();
    56→  const stderr = await new Response(proc.stderr).text();
    57→  const exitCode = await proc.exited;
    58→
    59→  console.error(`Return code: ${exitCode}`);
    60→  console.error(`Stdout length: ${stdout.length}`);
    61→  console.error(`Stderr: ${stderr.slice(0, 500) || "(empty)"}`);
    62→
    63→  if (exitCode !== 0) {
    64→    console.error(`Error running reviewer: ${stderr}`);
    65→    process.exit(1);
    66→  }
    67→
    68→  // Parse the outer JSON from claude CLI
    69→  let claudeOutput: Record<string, unknown>;
    70→  try {
    71→    claudeOutput = JSON.parse(stdout);
    72→  } catch (e) {
    73→    console.error(`Failed to parse claude output as JSON: ${e}`);
    74→    console.error(`Raw output: ${stdout.slice(0, 500)}`);
    75→    process.exit(1);
    76→  }
    77→
    78→  // Extract the result field
    79→  if (!("result" in claudeOutput)) {
    80→    console.error("No 'result' field in claude output");
    81→    process.exit(1);
    82→  }
    83→
    84→  const reviewerOutput = claudeOutput.result;
    85→
    86→  if (typeof reviewerOutput === "object" && reviewerOutput !== null) {
    87→    return reviewerOutput as Record<string, unknown>;
    88→  }
    89→
    90→  // Try to parse as JSON string
    91→  if (typeof reviewerOutput === "string") {
    92→    try {
    93→      return JSON.parse(reviewerOutput);
    94→    } catch {
    95→      // Try to extract JSON from the response
    96→      const match = /\{[\s\S]*\}/.exec(reviewerOutput);
    97→      if (match) {
    98→        return JSON.parse(match[0]);
    99→      }
   100→    }
   101→  }
   102→
   103→  console.error("Could not extract JSON from reviewer output");
   104→  console.error(`Output: ${String(reviewerOutput).slice(0, 500)}`);
   105→  process.exit(1);
   106→}
