   108→function parseReviewResult(
   109→  skillName: string,
   110→  data: Record<string, unknown>
   111→): ReviewResult {
   112→  const findings: Finding[] = [];
   113→  const rawFindings = data.findings;
   114→
   115→  if (Array.isArray(rawFindings)) {
   116→    for (const f of rawFindings) {
   117→      if (typeof f !== "object" || f === null) continue;
   118→      const finding = f as Record<string, unknown>;
   119→
   120→      let location: Location | null = null;
   121→      if (finding.location && typeof finding.location === "object") {
   122→        const loc = finding.location as Record<string, unknown>;
   123→        if (typeof loc.file === "string" && typeof loc.line === "number") {
   124→          location = {
   125→            file: loc.file,
   126→            line: loc.line,
   127→            endLine: typeof loc.endLine === "number" ? loc.endLine : undefined,
   128→          };
   129→        }
   130→      }
   131→
   132→      findings.push({
   133→        requirement: String(finding.requirement || ""),
   134→        status: String(finding.status || "info"),
   135→        severity: String(finding.severity || "info"),
   136→        details: String(finding.details || ""),
   137→        location,
   138→      });
   139→    }
   140→  }
   141→
   142→  return {
   143→    reviewerName: skillName,
   144→    status: String(data.status || "warn"),
   145→    summary: String(data.summary || ""),
   146→    findings,
   147→  };
   148→}
