   150→export async function handler(options: ReviewOptions): Promise<void> {
   151→  const prNumber = options.pr ?? (await getCurrentPR());
   152→  if (!prNumber) {
   153→    console.error("Could not detect PR number. Use --pr to specify.");
   154→    process.exit(1);
   155→  }
   156→
   157→  const baseBranch = options.base ?? "main";
   158→  const dryRun = options.dryRun ?? false;
   159→
   160→  console.log(`Running reviewer '${options.skill}' for PR #${prNumber}...`);
   161→
   162→  // Get diff lines for validation
   163→  const diffLines = await getDiffLines(baseBranch);
   164→
   165→  // Run the reviewer
   166→  const rawResult = await runReviewer(options.skill);
   167→  const result = parseReviewResult(options.skill, rawResult);
   168→
   169→  console.log(`Review complete: ${result.status.toUpperCase()} - ${result.summary}`);
   170→  console.log(`Found ${result.findings.length} finding(s)`);
   171→
   172→  // Separate findings with and without locations
   173→  const diffFindings: Finding[] = [];
   174→  const generalFindings: Finding[] = [];
   175→
   176→  for (const finding of result.findings) {
   177→    if (finding.location) {
   178→      const fileLines = diffLines.get(finding.location.file);
   179→      if (fileLines?.has(finding.location.line)) {
   180→        diffFindings.push(finding);
   181→      } else {
   182→        console.log(
   183→          `  Note: ${finding.location.file}:${finding.location.line} not in diff, adding to general findings`
   184→        );
   185→        generalFindings.push(finding);
   186→      }
   187→    } else {
   188→      generalFindings.push(finding);
   189→    }
   190→  }
   191→
   192→  // Post diff comments
   193→  for (const finding of diffFindings) {
   194→    const success = await postDiffComment(prNumber, finding, dryRun);
   195→    if (!success) {
   196→      generalFindings.push(finding);
   197→    }
   198→  }
   199→
   200→  // Post/update the main PR comment
   201→  await updateOrCreateComment(
   202→    prNumber,
   203→    result.reviewerName,
   204→    result.status,
   205→    result.summary,
   206→    generalFindings,
   207→    dryRun
   208→  );
   209→
   210→  // Print PR link
   211→  const prUrl = await getPRUrl(prNumber);
   212→  if (prUrl) {
   213→    console.log(`\nPR: ${prUrl}`);
   214→  } else {
   215→    console.log(`\nDone! (PR #${prNumber})`);
   216→  }
   217→}
