   219→export function builder(yargs: unknown): unknown {
   220→  return (yargs as { positional: Function; option: Function })
   221→    .positional("skill", {
   222→      describe: "Name of the reviewer skill to run (e.g., vibereq:code-review)",
   223→      type: "string",
   224→      demandOption: true,
   225→    })
   226→    .option("pr", {
   227→      describe: "PR number (auto-detected if not specified)",
   228→      type: "number",
   229→    })
   230→    .option("dry-run", {
   231→      describe: "Print what would be posted without actually posting",
   232→      type: "boolean",
   233→      default: false,
   234→    })
   235→    .option("base", {
   236→      describe: "Base branch for diff comparison",
   237→      type: "string",
   238→      default: "main",
   239→    });
   240→}
