    27→export async function getCurrentPR(): Promise<number | null> {
    28→  // GitHub Actions sets GITHUB_EVENT_PATH with the event payload
    29→  if (process.env.GITHUB_EVENT_NAME === "pull_request") {
    30→    const eventPath = process.env.GITHUB_EVENT_PATH;
    31→    if (eventPath) {
    32→      try {
    33→        const file = Bun.file(eventPath);
    34→        const event = await file.json();
    35→        const prNumber = event?.pull_request?.number;
    36→        if (typeof prNumber === "number") {
    37→          return prNumber;
    38→        }
    39→      } catch {
    40→        // Fall through to gh CLI
    41→      }
    42→    }
    43→  }
    44→
    45→  // Try to get PR from gh CLI
    46→  const result = await runCommand([
    47→    "gh",
    48→    "pr",
    49→    "view",
    50→    "--json",
    51→    "number",
    52→    "-q",
    53→    ".number",
    54→  ]);
    55→  if (result.exitCode === 0 && /^\d+$/.test(result.stdout.trim())) {
    56→    return parseInt(result.stdout.trim(), 10);
    57→  }
    58→
    59→  return null;
    60→}
    61→
    62→export async function getDiffLines(
    63→  baseBranch = "main"
    64→): Promise<Map<string, Set<number>>> {
    65→  const result = await runCommand([
    66→    "git",
    67→    "diff",
    68→    `${baseBranch}...HEAD`,
    69→    "--unified=0",
    70→  ]);
    71→  if (result.exitCode !== 0) {
    72→    return new Map();
    73→  }
    74→
    75→  const diffLines = new Map<string, Set<number>>();
    76→  let currentFile: string | null = null;
    77→
    78→  for (const line of result.stdout.split("\n")) {
    79→    // Match file header: +++ b/path/to/file.ts
    80→    if (line.startsWith("+++ b/")) {
    81→      currentFile = line.slice(6);
    82→      diffLines.set(currentFile, new Set());
    83→    }
    84→    // Match hunk header: @@ -old,count +new,count @@
    85→    else if (line.startsWith("@@") && currentFile) {
    86→      const match = /\+(\d+)(?:,(\d+))?/.exec(line);
    87→      if (match) {
    88→        const start = parseInt(match[1], 10);
    89→        const count = match[2] ? parseInt(match[2], 10) : 1;
    90→        const fileLines = diffLines.get(currentFile)!;
    91→        for (let i = start; i < start + count; i++) {
    92→          fileLines.add(i);
    93→        }
    94→      }
    95→    }
    96→  }
    97→
    98→  return diffLines;
    99→}
