   101→export async function getExistingReviewComment(
   102→  prNumber: number
   103→): Promise<{ nodeId: string; body: string } | null> {
   104→  const result = await runCommand([
   105→    "gh",
   106→    "api",
   107→    `/repos/{owner}/{repo}/issues/${prNumber}/comments`,
   108→    "--jq",
   109→    ".[] | {node_id: .node_id, body: .body}",
   110→  ]);
   111→
   112→  if (result.exitCode !== 0) return null;
   113→
   114→  for (const line of result.stdout.trim().split("\n")) {
   115→    if (!line) continue;
   116→    try {
   117→      const comment = JSON.parse(line);
   118→      if (comment.body?.startsWith(REVIEW_COMMENT_HEADER)) {
   119→        return { nodeId: comment.node_id, body: comment.body };
   120→      }
   121→    } catch {
   122→      continue;
   123→    }
   124→  }
   125→
   126→  return null;
   127→}
