   129→function formatFindingForDiffComment(finding: Finding): string {
   130→  const severityEmoji = SEVERITY_EMOJI[finding.severity] || "";
   131→  const statusEmoji = STATUS_EMOJI[finding.status] || "";
   132→
   133→  return [
   134→    `${severityEmoji} **${finding.requirement}**`,
   135→    `Status: ${statusEmoji} ${finding.status}`,
   136→    "",
   137→    finding.details,
   138→  ].join("\n");
   139→}
