   141→export async function postDiffComment(
   142→  prNumber: number,
   143→  finding: Finding,
   144→  dryRun = false
   145→): Promise<boolean> {
   146→  if (!finding.location) return false;
   147→
   148→  const body = formatFindingForDiffComment(finding);
   149→
   150→  if (dryRun) {
   151→    console.log(
   152→      `[DRY RUN] Would post diff comment on ${finding.location.file}:${finding.location.line}`
   153→    );
   154→    console.log(`  Body: ${body.slice(0, 100)}...`);
   155→    return true;
   156→  }
   157→
   158→  // Get commit SHA
   159→  const shaResult = await runCommand([
   160→    "gh",
   161→    "pr",
   162→    "view",
   163→    String(prNumber),
   164→    "--json",
   165→    "headRefOid",
   166→    "-q",
   167→    ".headRefOid",
   168→  ]);
   169→  if (shaResult.exitCode !== 0) {
   170→    console.error(`Failed to get PR head commit: ${shaResult.stderr}`);
   171→    return false;
   172→  }
   173→  const commitSha = shaResult.stdout.trim();
   174→
   175→  // Build the gh api command
   176→  const cmd = [
   177→    "gh",
   178→    "api",
   179→    "-X",
   180→    "POST",
   181→    `/repos/{owner}/{repo}/pulls/${prNumber}/comments`,
   182→    "-f",
   183→    `body=${body}`,
   184→    "-f",
   185→    `commit_id=${commitSha}`,
   186→    "-f",
   187→    `path=${finding.location.file}`,
   188→  ];
   189→
   190→  // Handle multi-line ranges
   191→  if (
   192→    finding.location.endLine &&
   193→    finding.location.endLine !== finding.location.line
   194→  ) {
   195→    cmd.push("-F", `start_line=${finding.location.line}`);
   196→    cmd.push("-F", `line=${finding.location.endLine}`);
   197→  } else {
   198→    cmd.push("-F", `line=${finding.location.line}`);
   199→  }
   200→
   201→  const result = await runCommand(cmd);
   202→
   203→  if (result.exitCode !== 0) {
   204→    console.log(
   205→      `Could not post diff comment (line may not be in diff): ${finding.location.file}:${finding.location.line}`
   206→    );
   207→    return false;
   208→  }
   209→
   210→  return true;
   211→}
