   213→function updateReviewSection(
   214→  existingBody: string,
   215→  reviewerName: string,
   216→  newSection: string
   217→): string {
   218→  const sectionHeader = `## ${reviewerName}`;
   219→  const escapedName = reviewerName.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
   220→  // Match section header followed by content, stopping at next section or end
   221→  // Use a more robust pattern that handles trailing newlines correctly
   222→  const pattern = new RegExp(
   223→    `## ${escapedName}\\n[\\s\\S]*?(?=\\n## |\\n*$)`
   224→  );
   225→
   226→  if (pattern.test(existingBody)) {
   227→    // Replace matched section, ensuring consistent trailing newline
   228→    const replacement = `${sectionHeader}\n${newSection.trimEnd()}`;
   229→    return existingBody.replace(pattern, replacement);
   230→  }
   231→  // Append new section, trimming any excessive trailing whitespace first
   232→  return `${existingBody.trimEnd()}\n\n${sectionHeader}\n${newSection.trimEnd()}`;
   233→}
