   235→async function updateCommentByNodeId(nodeId: string, body: string): Promise<boolean> {
   236→  const query = `
   237→    mutation UpdateComment($id: ID!, $body: String!) {
   238→      updateIssueComment(input: {id: $id, body: $body}) {
   239→        issueComment {
   240→          id
   241→        }
   242→      }
   243→    }
   244→  `;
   245→
   246→  const result = await runCommand([
   247→    "gh",
   248→    "api",
   249→    "graphql",
   250→    "-f",
   251→    `query=${query}`,
   252→    "-f",
   253→    `id=${nodeId}`,
   254→    "-f",
   255→    `body=${body}`,
   256→  ]);
   257→
   258→  return result.exitCode === 0;
   259→}
