   261→export function formatFindingForComment(finding: Finding): string {
   262→  const severityEmoji = SEVERITY_EMOJI[finding.severity] || "";
   263→  const statusEmoji = STATUS_EMOJI[finding.status] || "";
   264→
   265→  return [
   266→    `### ${severityEmoji} ${finding.requirement}`,
   267→    `**Status:** ${statusEmoji} ${finding.status} | **Severity:** ${finding.severity}`,
   268→    "",
   269→    finding.details,
   270→  ].join("\n");
   271→}
   272→
   273→export async function updateOrCreateComment(
   274→  prNumber: number,
   275→  reviewerName: string,
   276→  status: string,
   277→  summary: string,
   278→  findings: Finding[],
   279→  dryRun = false
   280→): Promise<void> {
   281→  const statusLine = `**Overall Status:** ${status.toUpperCase()}`;
   282→  const summaryLine = summary ? `\n${summary}` : "";
   283→
   284→  let sectionContent: string;
   285→  if (findings.length > 0) {
   286→    const findingsContent = findings
   287→      .map((f) => formatFindingForComment(f))
   288→      .join("\n\n");
   289→    sectionContent = `${statusLine}${summaryLine}\n\n${findingsContent}`;
   290→  } else {
   291→    sectionContent = `${statusLine}${summaryLine}\n\n_No general findings._`;
   292→  }
   293→
   294→  if (dryRun) {
   295→    console.log(`[DRY RUN] Would update PR comment for ${reviewerName}`);
   296→    console.log(`  Section content: ${sectionContent.slice(0, 200)}...`);
   297→    return;
   298→  }
   299→
   300→  const existing = await getExistingReviewComment(prNumber);
   301→
   302→  if (existing) {
   303→    const newBody = updateReviewSection(existing.body, reviewerName, sectionContent);
   304→
   305→    if (!(await updateCommentByNodeId(existing.nodeId, newBody))) {
   306→      console.error(
   307→        "Warning: Failed to update existing comment, creating new one"
   308→      );
   309→      const createBody = `${REVIEW_COMMENT_HEADER}\n\n## ${reviewerName}\n${sectionContent}`;
   310→      await runCommand([
   311→        "gh",
   312→        "pr",
   313→        "comment",
   314→        String(prNumber),
   315→        "--body",
   316→        createBody,
   317→      ]);
   318→    }
   319→  } else {
   320→    const newBody = `${REVIEW_COMMENT_HEADER}\n\n## ${reviewerName}\n${sectionContent}`;
   321→    await runCommand([
   322→      "gh",
   323→      "pr",
   324→      "comment",
   325→      String(prNumber),
   326→      "--body",
   327→      newBody,
   328→    ]);
   329→  }
   330→}
