    17→export async function getCommitsNotInMain(): Promise<string[]> {
    18→  const { stdout, exitCode } = await runGit([
    19→    "rev-parse",
    20→    "--is-inside-work-tree",
    21→  ]);
    22→  if (exitCode !== 0 || stdout.trim() !== "true") {
    23→    throw new Error("Not inside a git repository.");
