    `/repos/{owner}/{repo}/issues/${prNumber}/comments`,
    "--jq",
    ".[] | {node_id: .node_id, body: .body}",
  ]);

  if (result.exitCode !== 0) return null;

  for (const line of result.stdout.trim().split("\n")) {
    if (!line) continue;
