async function resolveReviewThread(threadId: string): Promise<boolean> {
  const query = `
    mutation ResolveThread($threadId: ID!) {
      resolveReviewThread(input: {threadId: $threadId}) {
        thread {
          id
        }
      }
    }
  `;

  const result = await runCommand([
    "gh",
    "api",
    "graphql",
    "-f",
    `query=${query}`,
    "-f",
    `threadId=${threadId}`,
  ]);

  return result.exitCode === 0;
}

async function getReviewThreads(
  prNumber: number
): Promise<Array<{ id: string; path: string; line: number }>> {
  const query = `
    query GetReviewThreads($owner: String!, $repo: String!, $pr: Int!) {
      repository(owner: $owner, name: $repo) {
        pullRequest(number: $pr) {
          reviewThreads(last: 100) {
            nodes {
              id
              isResolved
              path
              line
            }
          }
        }
      }
    }
  `;

  // Get owner and repo from gh
  const repoResult = await runCommand([
    "gh",
    "repo",
    "view",
    "--json",
    "owner,name",
  ]);
  if (repoResult.exitCode !== 0) return [];

  const repoInfo = JSON.parse(repoResult.stdout);
  const owner = repoInfo.owner.login;
  const repo = repoInfo.name;

  const result = await runCommand([
    "gh",
    "api",
    "graphql",
    "-f",
    `query=${query}`,
    "-f",
    `owner=${owner}`,
    "-f",
    `repo=${repo}`,
    "-F",
    `pr=${prNumber}`,
  ]);

  if (result.exitCode !== 0) return [];

  try {
    const data = JSON.parse(result.stdout);
    const threads = data.data.repository.pullRequest.reviewThreads.nodes;
    return threads
      .filter((t: { isResolved: boolean }) => !t.isResolved)
      .map((t: { id: string; path: string; line: number }) => ({
        id: t.id,
        path: t.path,
        line: t.line,
      }));
  } catch {
    return [];
  }
}

export async function submitReview(
  prNumber: number,
  result: ReviewResult,
  diffFindings: Finding[],
  generalFindings: Finding[],
  dryRun = false
): Promise<{ success: boolean; failedFindings: Finding[] }> {
  const failedFindings: Finding[] = [];

  // Build review comments from diff findings
  const comments: ReviewComment[] = [];
  const fulfilledComments: Array<{ path: string; line: number }> = [];

  for (const finding of diffFindings) {
    const comment = buildReviewComment(finding);
    if (comment) {
      comments.push(comment);
      if (finding.status === "fulfilled") {
        fulfilledComments.push({ path: comment.path, line: comment.line });
      }
    } else {
      failedFindings.push(finding);
    }
  }

  // Build review body from general findings and summary
  const reviewBody = formatReviewBody(result, generalFindings);

  if (dryRun) {
    console.log(`[DRY RUN] Would submit review with ${comments.length} diff comment(s)`);
    for (const comment of comments) {
      console.log(`  - ${comment.path}:${comment.line}`);
    }
    console.log(`[DRY RUN] Review body preview: ${reviewBody.slice(0, 200)}...`);
    if (fulfilledComments.length > 0) {
      console.log(`[DRY RUN] Would resolve ${fulfilledComments.length} fulfilled comment(s)`);
    }
    return { success: true, failedFindings };
  }

  const commitSha = await getCommitSha(prNumber);
  if (!commitSha) {
    return { success: false, failedFindings: [...diffFindings, ...generalFindings] };
  }

  // Build the review payload
  const payload: Record<string, unknown> = {
    commit_id: commitSha,
    body: reviewBody,
    event: "COMMENT",
  };

  if (comments.length > 0) {
    payload.comments = comments;
  }

  // Write payload to temp file for gh api
  const tempFile = `/tmp/vibx-review-${Date.now()}.json`;
  await Bun.write(tempFile, JSON.stringify(payload));

  const createResult = await runCommand([
    "gh",
    "api",
    "-X",
    "POST",
    `/repos/{owner}/{repo}/pulls/${prNumber}/reviews`,
    "--input",
    tempFile,
  ]);

  // Clean up temp file
  try {
    await Bun.file(tempFile).exists() && (await runCommand(["rm", tempFile]));
  } catch {
    // Ignore cleanup errors
  }

  if (createResult.exitCode !== 0) {
    console.error(`Failed to create review: ${createResult.stderr}`);
    return { success: false, failedFindings: [...diffFindings, ...generalFindings] };
  }

  console.log(`Created review with ${comments.length} diff comment(s)`);

  // Resolve fulfilled comments
  if (fulfilledComments.length > 0) {
    console.log(`Resolving ${fulfilledComments.length} fulfilled comment(s)...`);
    const threads = await getReviewThreads(prNumber);

    for (const fulfilled of fulfilledComments) {
      const thread = threads.find(
        (t) => t.path === fulfilled.path && t.line === fulfilled.line
      );
      if (thread) {
        const resolved = await resolveReviewThread(thread.id);
        if (resolved) {
          console.log(`  Resolved: ${fulfilled.path}:${fulfilled.line}`);
        }
      }
    }
  }

  return { success: true, failedFindings };
}

function formatReviewBody(result: ReviewResult, generalFindings: Finding[]): string {
  const statusEmoji =
    result.status === "pass"
      ? ":white_check_mark:"
      : result.status === "fail"
        ? ":x:"
        : ":warning:";

  const lines = [
    `${REVIEW_COMMENT_HEADER}`,
    "",
    `## ${result.reviewerName}`,
    `**Overall Status:** ${statusEmoji} ${result.status.toUpperCase()}`,
  ];

  if (result.summary) {
    lines.push("", result.summary);
  }

  if (generalFindings.length > 0) {
    lines.push("", "### General Findings", "");
    for (const finding of generalFindings) {
      lines.push(formatFindingForComment(finding), "");
    }
  }

  return lines.join("\n");
}

function updateReviewSection(
  existingBody: string,
  reviewerName: string,
  newSection: string
): string {
  const sectionHeader = `## ${reviewerName}`;
  const escapedName = reviewerName.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  // Match section header followed by content, stopping at next section or end
  // Use a more robust pattern that handles trailing newlines correctly
  const pattern = new RegExp(
    `## ${escapedName}\\n[\\s\\S]*?(?=\\n## |\\n*$)`
  );

  if (pattern.test(existingBody)) {
    // Replace matched section, ensuring consistent trailing newline
    const replacement = `${sectionHeader}\n${newSection.trimEnd()}`;
    return existingBody.replace(pattern, replacement);
  }
  // Append new section, trimming any excessive trailing whitespace first
  return `${existingBody.trimEnd()}\n\n${sectionHeader}\n${newSection.trimEnd()}`;
}

async function updateCommentByNodeId(nodeId: string, body: string): Promise<boolean> {
  const query = `
    mutation UpdateComment($id: ID!, $body: String!) {
      updateIssueComment(input: {id: $id, body: $body}) {
        issueComment {
          id
        }
      }
    }
  `;

  const result = await runCommand([
    "gh",
    "api",
    "graphql",
    "-f",
    `query=${query}`,
    "-f",
    `id=${nodeId}`,
    "-f",
    `body=${body}`,
  ]);

  return result.exitCode === 0;
}

export function formatFindingForComment(finding: Finding): string {
  const severityEmoji = SEVERITY_EMOJI[finding.severity] || "";
  const statusEmoji = STATUS_EMOJI[finding.status] || "";

  return [
    `### ${severityEmoji} ${finding.requirement}`,
    `**Status:** ${statusEmoji} ${finding.status} | **Severity:** ${finding.severity}`,
    "",
    finding.details,
  ].join("\n");
}

export async function updateOrCreateComment(
  prNumber: number,
  reviewerName: string,
  status: string,
  summary: string,
  findings: Finding[],
  dryRun = false
): Promise<void> {
  const statusLine = `**Overall Status:** ${status.toUpperCase()}`;
  const summaryLine = summary ? `\n${summary}` : "";

  let sectionContent: string;
  if (findings.length > 0) {
    const findingsContent = findings
      .map((f) => formatFindingForComment(f))
      .join("\n\n");
    sectionContent = `${statusLine}${summaryLine}\n\n${findingsContent}`;
  } else {
    sectionContent = `${statusLine}${summaryLine}\n\n_No general findings._`;
  }

  if (dryRun) {
    console.log(`[DRY RUN] Would update PR comment for ${reviewerName}`);
    console.log(`  Section content: ${sectionContent.slice(0, 200)}...`);
    return;
  }

  const existing = await getExistingReviewComment(prNumber);

  if (existing) {
    const newBody = updateReviewSection(existing.body, reviewerName, sectionContent);

    if (!(await updateCommentByNodeId(existing.nodeId, newBody))) {
      console.error(
        "Warning: Failed to update existing comment, creating new one"
      );
      const createBody = `${REVIEW_COMMENT_HEADER}\n\n## ${reviewerName}\n${sectionContent}`;
      await runCommand([
        "gh",
        "pr",
        "comment",
        String(prNumber),
        "--body",
        createBody,
      ]);
    }
  } else {
    const newBody = `${REVIEW_COMMENT_HEADER}\n\n## ${reviewerName}\n${sectionContent}`;
    await runCommand([
      "gh",
      "pr",
      "comment",
      String(prNumber),
      "--body",
      newBody,
    ]);
  }
}

